var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"GUARD_EXTRA_NANA_A","text":{"KOREA":"참 희한하네요. 시간은 아침인데 아직도 달이 떠 있다니.","JPN":"珍しいですね。もう朝なのに月が見えます。","ENG":"That’s weird. It’s morning, and the moon is still there.","TWN":"真稀奇，明明是早上，卻還看得到月亮。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUARD_EXTRA_NANA_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"GUARD_EXTRA_NANA_B","text":{"KOREA":"그래. 세상이 망하려는 징조겠지.","JPN":"そうだな。この世の終わりの兆しだろう。","ENG":"Yes, it must be a sign that the world is coming to an end.","TWN":"是啊。這是世界末日的徵兆吧？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_EXTRA_NANA_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUARD_EXTRA_NANA_B","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"GUARD_EXTRA_NANA_B","text":{"KOREA":"하아, 가족들과 함께 있어도 아쉬울 때에 감옥이나 지키고 있어야 하다니. 내 팔자야.","JPN":"はあ、こんな時だからこそ家族と一緒にいたいのに、牢屋を見張ってないといけないとは。最悪だな。","ENG":"*Sigh* I’m supposed to be with my family, but here I am, guarding this prison cell.","TWN":"哀哀，明明應該要把握時間跟家人在一起，但我卻只能守著這個監牢，我還真命苦！"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_EXTRA_NANA_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUARD_EXTRA_NANA_B","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"GUARD_EXTRA_NANA_A","text":{"KOREA":"재수없는 소리 좀 하지 마세요.","JPN":"縁起でもないことを言わないでください。","ENG":"Stop being so ominous.","TWN":"別說這種不吉利的話。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_EXTRA_NANA_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUARD_EXTRA_NANA_B","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"GUARD_EXTRA_NANA_A","text":{"KOREA":"연합이 어떻게든 해결할 겁니다. 옛 선조들이 그래왔던 것처럼요.","JPN":"連合がなんとか解決しますよ。ご先祖様がそうしてきたように。","ENG":"The Alliance will handle it. Like our ancestors did.","TWN":"聯盟無論如何都會解決的。就像以前祖先們那樣。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_EXTRA_NANA_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUARD_EXTRA_NANA_B","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"GUARD_EXTRA_NANA_B","text":{"KOREA":"흥. 3년 전 추방계획 때도 다들 그럴 거라고 믿었어.","JPN":"フン、3年前の追放計画の時もみんなそう信じて疑わなかったんだ。","ENG":"Hmpf. That’s what everyone said three years ago.","TWN":"哼，3年前驅逐計劃的時候，大家也都深信不疑。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_EXTRA_NANA_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUARD_EXTRA_NANA_B","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"GUARD_EXTRA_NANA_B","text":{"KOREA":"나나하라 당주 말만 듣고 오로치를 추방하려 했다가 봉인이 약해지는 바람에 거의 전멸할 뻔했지.","JPN":"七原家当主の言葉を信じてオロチを追放しようとしたが、\\n封印が弱まったせいで全滅寸前だったんだぞ。","ENG":"They went to purge Orochi on Lady Nanahara’s say-so, and they were all but wiped out due to the weakened seal.","TWN":"聽了七原堂主的話想要驅逐大蛇，結果封印變弱，搞得差點全軍覆沒。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUARD_EXTRA_NANA_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"GUARD_EXTRA_NANA_B","text":{"KOREA":"그 사건 때 죽은 당주들 자리엔 죄다 풋내기들뿐이야.","JPN":"あの事件で命を落とした当主の後任は、みんな青臭いヤツばかりだ。","ENG":"So many family leaders died on that day, and all we have left is their cubs.","TWN":"在那次事件中死去堂主的位子，全都是初出茅廬的傢伙接任的。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUARD_EXTRA_NANA_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"GUARD_EXTRA_NANA_B","text":{"KOREA":"제대로 배운 것 하나 없이, 책임만 물려받은 꼬맹이들이라고.","JPN":"まともな修行もできずに責任だけを押し付けられたガキどもなんだよ。","ENG":"Kids who inherited the responsibility without any proper education.","TWN":"他們什麼都沒學到，只有繼承責任。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUARD_EXTRA_NANA_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"GUARD_EXTRA_NANA_A","text":{"KOREA":"그 치들도 딱하죠. 어린 것들에게 무슨 잘못이 있겠습니까.","JPN":"気の毒ですね。まだ子どもだというのに。","ENG":"I feel sorry for them. They are still children who need care and support.","TWN":"他們也很可憐，孩子有什麼錯呢？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_EXTRA_NANA_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUARD_EXTRA_NANA_B","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"GUARD_EXTRA_NANA_B","text":{"KOREA":"정신 차려. 연민이 밥 먹여주나?","JPN":"何言ってんだよ、哀れむ必要なんかない！","ENG":"Wake up. Sympathy won’t save your butt.","TWN":"你清醒一點，同情能當飯吃嗎？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_EXTRA_NANA_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUARD_EXTRA_NANA_B","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"GUARD_EXTRA_NANA_B","text":{"KOREA":"오로치가 깨어나기라도 해 봐. 그 꼬마들만 남겨 두고 우린 전부 죽을걸.","JPN":"オロチが目を覚ましてみろ。\\nそいつらだけ残して俺たちは皆殺しだぞ。","ENG":"What if Orochi wakes up? Everyone will die except for those kids.","TWN":"等大蛇醒過來，只會留下那些小鬼，我們全都會沒命的。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_EXTRA_NANA_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUARD_EXTRA_NANA_B","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"GUARD_EXTRA_NANA_A","text":{"KOREA":"그렇다고는 해도…… 음?","JPN":"それはそうですが……あれ？","ENG":"But still—huh?","TWN":"就算是這樣……嗯？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_EXTRA_NANA_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUARD_EXTRA_NANA_B","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"GUARD_EXTRA_NANA_A","text":{"KOREA":"저, 저기! 창고 위로 솟구치는 저거! 불 아닙니까?!","JPN":"あ、あそこ！　倉庫の屋根から出てるあれ！　火じゃないですか！？","ENG":"L-look at the warehouse! It’s on fire!","TWN":"那…那個！竄到倉庫上面的是什麼！是火舌嗎？！"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUARD_EXTRA_NANA_A","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_SIREN"},{"id":"L22_1","type":"dialog","speaker":"GUARD_EXTRA_NANA_B","text":{"KOREA":"뭐? 폭발도 없었는데 갑자기 무슨 화재야?","JPN":"え？　爆発音もなかったのに急に火災だと？","ENG":"What? I didn’t hear an explosion. Where did that come from?","TWN":"什麼？又沒有爆炸，怎麼會突然著火？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUARD_EXTRA_NANA_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"GUARD_EXTRA_NANA_B","text":{"KOREA":"소화 장치는 고장난 건가? 당장 소화기부터 찾아!","JPN":"消火装置は故障でもしたのか？　急いで消火器を持って来い！","ENG":"What happened to the automatic sprinkler system? Find a fire extinguisher! Quick!","TWN":"滅火器故障了嗎？趕快先找滅火器吧！"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUARD_EXTRA_NANA_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"훗. 멋지게 시선을 끌었군.","JPN":"フッ、最高のおとりになったな。","ENG":"Hah, they are all distracted.","TWN":"嘿嘿，調虎離山之計成功！"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L29_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"밖이 소란스럽더군요. 무슨 일이라도 생겼습니까?","JPN":"外が騒がしいですね。何かあったのですか？","ENG":"What is that noise? What’s happening?","TWN":"外面好像有點吵，發生什麼事了嗎？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L31_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"금제에 구속된 처지라기엔 태연한 반응이군, 죄 많은 여인이여.","JPN":"牢に拘束された身にしてはずいぶんと余裕があるな、罪深き女よ。","ENG":"Sinful woman, you seem very peaceful for being caged in the forbidden prison.","TWN":"明明被關在監牢裡，但你的反應很淡定呢！你這罪惡多端的女人！"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"……부디 평범하게 말씀해 주시지요. 카토리 당주님.","JPN":"……香取家当主様、どうか普通の口調でお話しください。","ENG":"Please talk plainly, Mr. Katori.","TWN":"……說話請正常一點，香取堂主。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"저는 괜찮습니다. 이곳에 돌아오기로 했을 때부터 모함은 각오하고 있었으니까요.","JPN":"私は大丈夫です。\\nここに帰ると決めた時から、謀略にかけられる覚悟はしていましたから。","ENG":"I’m fine as is. I knew something like this would happen when I came back here.","TWN":"我沒事，當我決定要回到這裡時，就已經做好會被誣陷的心理準備。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"모략에 시달리는 것쯤은 익숙하다는 건가? 재미있군!","JPN":"謀略に苦しむことに慣れてるってことか。面白い！","ENG":"So you’re already accustomed to their schemes? Interesting!","TWN":"意思是你已經很習慣被算計嗎？ 有意思！"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"한평생 어미가 진 업의 대가를 치르는 것만으로도 부족한 몸입니다.","JPN":"母が犯した罪は、一生をかけても償いきれません。","ENG":"That’s because I know I have to pay for my mother’s crime.","TWN":"我只想用這一生來償還家母欠下的債。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"실없는 대화나 나누러 오셨다면 이만 돌아가 주시죠.","JPN":"無駄話をしに来られたのでしたら、お引き取りください。","ENG":"If you’re here to mock me, please leave.","TWN":"如果是來談一些沒意義的話，那就請回吧。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"훗. 어리석구나.","JPN":"フッ、愚かだな。","ENG":"Hah. Silly woman.","TWN":"呵，你的腦袋不太好呢。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"이 오오가미 흑막조장님께서 몸소 행차한 데에는 다 깊은 뜻이 있는 법.","JPN":"この大神黒幕組長が自ら来てやったのには深い意味がある。","ENG":"I, the boss of Ogami's Shadow Group, am here to see you for a reason.","TWN":"我黑幕組組長親自出馬，那肯定是有重要的事。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"……열쇠? 그걸 어디서 손에 넣으셨습니까?","JPN":"……鍵？　どこで手に入れたのですか？","ENG":"A key? Where did you get it?","TWN":"……鑰匙？你是從哪裡弄到手的？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_ALL_MISSILE_RELOAD"},{"id":"L47_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"나나하라 당주의 부탁이다. 죄 많은 여인을 금제의 뇌옥에서 풀어 달라더군.","JPN":"七原家当主の頼みだ。罪深き女を禁制の牢獄から解放してほしい、とな。","ENG":"From Lady Nanahara. She requested I free a sinner from the Forbidden Prison.","TWN":"是七原堂主拜託我的，她要我將罪惡多端的女人，從囚禁的牢籠裡釋放出來。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L48_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"당주님께서…….","JPN":"ご当主様が……","ENG":"Lady Nanahara...","TWN":"堂主……"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"저 같은 자를 위해 괜한 호의를 베푸셨군요.","JPN":"私ごときのために必要のない恩情を施されたのですね。","ENG":"She wastes her kindness on likes of me.","TWN":"不用把心思浪費在我這種人身上。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"하핫. 자만하지 말도록.","JPN":"ハハッ、うぬぼれるな。","ENG":"Hah, don’t be so arrogant.","TWN":"哈哈，不要太驕傲。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"이 역시 흑막조의 세력을 확장하기 위한 계획의 일환이니 말이다!","JPN":"これもまた黒幕組の勢力を拡大する計画の一環にすぎないからな。","ENG":"This is only to expand the influence of Ogami’s Shadow Group!","TWN":"這也是要擴張黑幕組勢力的部分計劃！"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"……음?","JPN":"……うん？","ENG":"Huh?","TWN":"……嗯？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L3_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"당주님, 뒤에!","JPN":"当主様、後ろです！","ENG":"Lady, behind you!","TWN":"堂主，小心後面！"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L5_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"뒤?","JPN":"後ろ？","ENG":"Behind me?","TWN":"後面？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"끄응……. 뒤통수가 깨질 것 같아.","JPN":"ううっ……頭が割れそう。","ENG":"Aw... my head...","TWN":"嗚……後腦勺好痛。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"뭐야……? 왜 내가 감옥 안에 들어와 있는 거지?","JPN":"なんだ……？　どうしてオレが牢屋の中にいるんだ？","ENG":"Huh? Why am I in prison?","TWN":"怎麼會…？我為什麼會在監牢裡？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L12_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"경비병에게 공격 받으셨습니다. 정신이 들어 다행이군요.","JPN":"気がつかれてよかったです。警備兵に攻撃されたのですよ。","ENG":"The guardsman attacked you. I’m glad you’re awake.","TWN":"你剛受到警衛兵的攻擊，人沒事就好。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"잠시만 이쪽을 보시지요.","JPN":"少しじっとしてください。","ENG":"Look at me, please.","TWN":"你看我這邊。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"뭐, 뭐 하는 거야? 얼굴이 너무 가깝잖아!","JPN":"な、何してるんだ！？　顔が近すぎるだろ！","ENG":"W-what are you doing? It’s too close!","TWN":"你…你靠這麼近幹嘛啦！"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"다행이군요. 눈동자로 보아 가벼운 뇌진탕이었습니다.","JPN":"よかったです。\\n瞳を観察させていただきましたが、ただの脳震盪のようですね。","ENG":"Based on the movement of your pupils, I’d say it's just a mild concussion.","TWN":"幸好，從瞳孔看來只有輕微腦震盪。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L20_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"흑막조의 수장인 날 당황하게 하다니……. 역시 평범한 여인은 아니군.","JPN":"黒幕組の長であるオレ様を動揺させるとは……\\nやはり、ただの女ではないな。","ENG":"You dare embarrass the boss of Ogami’s Shadow Group? You really aren’t an ordinary woman.","TWN":"竟然可以讓我這個黑幕組的組長嚇到……果然不是平凡的女人。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L21_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"평범하고 비범하고는 구분할 가치가 없습니다. 저는 그저 제 역할을 다할 뿐이지요.","JPN":"平凡、非凡と区別する意味はございません。\\n私はただ自分の役割を全うするだけです。","ENG":"Being ordinary or not isn’t really important. I’m only doing my job.","TWN":"沒必要分平凡或不平凡。我只是盡我的本份而已。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"하야미 가문의 역할은 당주들의 신변 보호였다지.","JPN":"速水家の役割は当主の護衛だったそうだな。","ENG":"Hayami family was responsible for the protection of Nanahara family leaders.","TWN":"速水家族的本份是保護堂主的人身安全。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"당주 암살 모의로 잡혀 있는 자가 할 소리는 아니군. 뻔뻔함에 소름이 끼칠 정도다.","JPN":"当主暗殺を企てて拘束された者が言うことではないな。\\n面の皮の厚さに鳥肌が立つくらいだ。","ENG":"Yet you’re here to attempt to assassinate Lady Nanahara. You’re truly shameless.","TWN":"身為策劃要暗殺堂主的幕後主使人，竟然說得出口這種話，你臉皮厚到我起雞皮疙瘩呢。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"당주님께선 제가 연합과의 불화를 피할 수 있도록 여러모로 도움을 주셨습니다.","JPN":"ご当主様は私と連合の間に不和が生まれぬようお力添えくださいました。","ENG":"Lady Nanahara helped me to avoid conflicts with other families.","TWN":"堂主一直在幫助我避開與聯盟的紛爭。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"하오니 제게는 그분께 해가 되는 행동을 할 이유가 없습니다.","JPN":"ですので、私にはあのお方に害を及ぼす理由はありません。","ENG":"Why would I hurt her?","TWN":"因此我沒有理由做出傷害她的行爲。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"훗. 얄팍한 변명이군.","JPN":"フン、浅はかな言い訳だな。","ENG":"Hah. That’s a lame excuse.","TWN":"哈，這理由還真薄弱。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"그렇다면 어째서 항의 한 번 하지 않고 얌전히 투옥됐지?","JPN":"だったらどうして反抗せずに大人しく投獄されたんだ？","ENG":"Then why didn’t you protest when they put you here?","TWN":"那你為什麼都不為自己辯解，就這樣乖乖坐牢？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"한 번은.","JPN":"かつて。","ENG":"I did once.","TWN":"有一次，"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"제가 아직 어린 계집아이일 적에 어미의 누명을 풀어 달라고 항변했지요.","JPN":"私がまだ幼い頃に、母の濡れ衣を晴らしてほしいと訴えたことがあります。","ENG":"When I was very young, I protested for my mother’s innocence.","TWN":"當時我還小，我為家母辯護說她是清白的。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"하지만 장로께서 보여 주신 선대 당주님의 시신에는 제 어미의 무기가 할퀴고 간 흔적들이 또렷했습니다.","JPN":"ですが、長老が見せてくださった先代当主のご遺体には、\\n母の武器の痕がはっきりと残っていました。","ENG":"Then the elders showed me the dead body of the previous Nanahara family leader, who was clearly killed by my mother’s weapon.","TWN":"但長老把先祖堂主的屍體給我看，屍體上很明顯有家母武器留下的痕跡。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"선대 당주께선…… 하야미 가문 때문에, 제 어미 손에 돌아가신 겁니다.","JPN":"先代当主は……速水家のせいで、私の母のせいで命を落とされたのです。","ENG":"She died... because of my family, because of my mother.","TWN":"先祖堂主……是被速水家族…被家母害死的。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"그 일로 벌어진 참극을 생각하면, 연합 전체에 씻을 수 없는 죄를 저지른 격이지요.","JPN":"この惨劇を考えると、連合全体に償いきれない罪を犯してしまったようなものです。","ENG":"Considering the disastrous consequences it brought, the sin my family committed against the Alliance can never be redeemed.","TWN":"想到因為那件事而發生的慘劇，就等於是對整個聯盟犯下無法洗刷的罪。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"……그래서 누명인데도 가만히 있었다고?","JPN":"……だから濡れ衣なのに黙っていたのか？","ENG":"That’s why you didn’t protest against the false accusation?","TWN":"……所以就算被冤枉，你也不為自己辯解？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"어머니의 죄를 대신 속죄하려고?","JPN":"母親の罪を代わりに償うつもりで？","ENG":"So that you could pay for the crime your mother committed?","TWN":"是想替母親贖罪？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"제가 의심 받게 된 것 또한 어미에게 물려받은 업보입니다.","JPN":"私が疑われたのもまた、私が母から受け継いだ業です。","ENG":"That’s the karma my mother passed on to me.","TWN":"我會受到懷疑，也是因為家母的緣故。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"애초에 그 일이 없었더라면, 연합이 지금과 같이 혼란스럽지도 않았겠지요.","JPN":"そもそもあの出来事がなかったら、連合がこれほど混乱することもなかったでしょう。","ENG":"The Alliance wouldn’t have been like this if it wasn’t for my mother.","TWN":"如果沒有當初那件事，聯盟也不會像現在這樣混亂。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"받아라, 죄 많은 여인이여.","JPN":"受け取れ、罪深き女よ。","ENG":"Take this, sinful woman.","TWN":"拿去，罪惡多端的女人。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L49_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"이것은……?","JPN":"これは……？","ENG":"What is this?","TWN":"這是……？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"충성스러운 흑막조원, 나유카 미나토가 너에게 그 가면을 전해 주라더군.","JPN":"忠実たる黒幕組の一員、奈由香湊から\\n貴様にその面を渡してくれと頼まれた。","ENG":"My loyal subject, Nayuka Minato, asked me to give you this mask.","TWN":"忠誠的黑幕組組員 南裕夏，要我把這個面具轉交給你。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"구해 준 은혜를 갚겠다면서 말이다.","JPN":"助けてもらった恩返しとのことだ。","ENG":"He wanted to repay you for what you did for him.","TWN":"說是要報答救命之恩。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"……저에겐 필요 없는 것입니다.","JPN":"……私には必要ないものです。","ENG":"... I don’t need it.","TWN":"……我不需要這個。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L5_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"훗. 오오카미 흑막조를 너무 우습게 봤군. 물론 나도 그게 쓸모없는 물건인 줄…….","JPN":"フッ、大神黒幕組を侮るな。\\nもちろんオレ様も、それが使えないものということぐらい……","ENG":"Do you take the Ogami’s Shadow Group for fools? I already know that you don’t need it...","TWN":"呵，這麼小看我們黑幕組！我也知道那個東西沒什麼用……"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L6_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"하지만, 차마 버리지도 못했던 것이지요.","JPN":"ですが、どうしても捨てることができなかったのです。","ENG":"But I just couldn’t throw it away.","TWN":"但是又捨不得丟掉。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L7_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"찾아 주셔서 감사합니다.","JPN":"見つけていただき、ありがとうございます。","ENG":"Thank you for bringing this to me.","TWN":"謝謝你來救我。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"크흠……! 흠!","JPN":"コホン……！　あ、ああ！","ENG":"Ahem, hmm.","TWN":"咳咳……！嗯！"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NULL","text":{"KOREA":"허허, 죄인끼리 꽤나 즐겁게 담소를 나누고 있었군.","JPN":"ハハハ、罪人同士で楽しく談笑しているようだな。","ENG":"Hah. I see criminals are having a pleasant conversation.","TWN":"呵呵，犯人還有時間在那談笑風生呢。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"장로!?","JPN":"長老！？","ENG":"Elder?!","TWN":"長老？！"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"큭……! 누구더러 죄인이라는 거냐! 당장 이거 열지 못해!","JPN":"くっ……！　誰が罪人だ！　今すぐここから出せ！","ENG":"Bah! I’m not a criminal! Open this door right now!","TWN":"咳…！你說誰是犯人！馬上給我打開！"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NULL","text":{"KOREA":"죄인이지. 탈옥도 모자라서 저 쥐새끼 같은 하야미의 여식까지 꺼내려 하다니.","JPN":"罪人だろう。　脱獄したあげく、速水家の娘に手を貸したのだからな。","ENG":"Yes, you are. You broke out of jail, and you even tried to get this Hayami woman out of her cell.","TWN":"不是犯人是什麼？自己逃獄就算了，竟然還想把速水的女兒一起帶走！"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NULL","text":{"KOREA":"어떻게 처리할지 고민할 필요도 없게 알아서 일을 저질러 주는군. 허허.","JPN":"処罰について悩む必要がないように、自分からしっぽを出すとはな。ハハハ。","ENG":"Now we don’t even have to come up with any plan. Hah hah.","TWN":"都不用我出手，你們就自己送上門　呵呵。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"태평하게 웃을 때냐? 곧 오로치가 깨어나 세상을 뒤집어 버릴지도 모르는데!","JPN":"呑気に笑ってる場合か！？　もうすぐオロチが目覚めて世界をめちゃくちゃにするかもしれないんだぞ！","ENG":"What’s so funny? Orochi is coming back to destroy the world!","TWN":"你還笑得出來？說不定大蛇馬上就會醒來，把這裡搞得翻天覆地的！"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"한 명이라도 아쉬울 상황에 사람들을 잡아 가둬?","JPN":"人手が足りない時に俺たちを閉じ込めておくのか？","ENG":"You need everyone to fight against Orochi, yet you lock me up here?","TWN":"現在應該是正需要人手的時候，你們還把人抓起來？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NULL","text":{"KOREA":"오로치라…….","JPN":"オロチか……","ENG":"Orochi...","TWN":"大蛇嗎……"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NULL","text":{"KOREA":"그걸 두려워해야 할 것은 자네들일 뿐. <color=#ffd34c>우리</color>는 예외지.","JPN":"それを恐れるのはお前たちだけ。<color=#ffd34c>我々</color>は例外だ。","ENG":"You should be afraid of Orochi, yes. But not <color=#ffd34c>us</color>.","TWN":"你們是該害怕沒錯，<color=#ffd34c>我們</color>是沒什麼好怕的。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"우리…… 라고? 그게 무슨 소리냐?","JPN":"我々……？　どういう意味だ？","ENG":"Us? What do you mean?","TWN":"我們……？那是什麼意思？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NULL","text":{"KOREA":"흐흐, 배나 몰던 천박한 핏줄은 어쩔 수 없구나.","JPN":"フフフ、下賤な船乗りの血筋は仕方がないな。","ENG":"Hah hah, what can you expect from a lowly family of boatsmen.","TWN":"呵呵，真拿你們這些船夫沒辦法。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NULL","text":{"KOREA":"아직도 네 아비가 나나하라 당주 때문에 죽었다고 생각하느냐?","JPN":"まだお前の父親が七原家当主のせいで死んだと思っているのか？","ENG":"Do you still believe your father died because of Lady Nanahara?","TWN":"你真以為你父親是因爲七原堂主而喪命的嗎？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"뭐라고……?","JPN":"何だと……！？","ENG":"What?","TWN":"你說什麼……？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"어이, 영감탱이! 아버지에 대해 뭘 알고 있는 거야!","JPN":"おい、クソジジイ！　親父について何を知っている！","ENG":"Hey, old man! What do you know about my father’s death?","TWN":"喂，臭老頭！你知道什麼！"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NULL","text":{"KOREA":"네 아비도, 너도. 너희 카토리 가문 놈들은 하나같이 마음에 들지 않았어.","JPN":"お前の父親も、お前も。\\nお前たち香取家の奴らは昔から気に食わなかった。","ENG":"Including your father and you, I always hated you Katoris.","TWN":"不管是你父親，或是你，你們香取家族的傢伙我沒一個滿意的！"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NULL","text":{"KOREA":"낡은 전통은 바꿔야 한다고 장로들을 무시하면서 나나하라 당주 꽁무니만 졸졸 따라다녔지.","JPN":"古い伝統は変えるべきだと主張して長老たちのことを無視し、\\n七原家当主にだけ尻尾を振ってついていった。","ENG":"You lot insulted the elders and their traditions, licking the Nanahara’s boots.","TWN":"瞧不起長老，在那邊說要改變傳統，只知道跟在七原堂主的後面當跟屁蟲。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NULL","text":{"KOREA":"치나츠의 혼사 건도 그랬지. 기껏 고관과 혼사를 잡았더니 기를 쓰고 반대하더군.","JPN":"千夏の婚礼の件もそうだった。\\n高官との婚礼を予定していたのに必死に反対していたな。","ENG":"When we tried to marry Chinatsu to a high ranking official, your family went against it.","TWN":"還有千夏的婚事也是，好不容易才搞定跟高官的婚事，他卻拼命反對。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NULL","text":{"KOREA":"그 더러운 기름때 묻은 손으로 내 멱살을 잡아챘을 때는…….","JPN":"あの薄汚れた手に胸ぐらを掴まれた時は……","ENG":"Your father even grabbed my throat with his dirty oily hands...","TWN":"用他沾滿油漬的髒手抓住我衣領的時候……"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NULL","text":{"KOREA":"그래. 그래서 오로치의 봉인을 조금 손봐 줬을 뿐이다.","JPN":"そうだ。それでオロチの封印に少し細工をしたのだ。","ENG":"Yes. That’s why we manipulated the seal of Orochi.","TWN":"沒錯，我只是對大蛇的封印動了些手腳而已。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"봉인을 손봤다고?","JPN":"封印に細工だと？","ENG":"You manipulated the seal?","TWN":"對封印動手腳？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"설마, 추방계획 때 봉인이 약해졌던 게……!","JPN":"まさか、追放計画の時に封印が弱まったのは……！","ENG":"Wait, then the seal was weakened during the purging operation because...","TWN":"難道，驅逐計劃時封印會變弱……！"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NULL","text":{"KOREA":"그래. 덕분에 연합에는 좋은 본보기가 됐지.","JPN":"そうだ。おかげで連合のいい見せしめになった。","ENG":"Yes, it set a good example for the Alliance.","TWN":"沒錯。我還因此成為聯盟的榜樣。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NULL","text":{"KOREA":"치나츠, 그 건방진 꼬맹이도 그때부턴 얌전해지더구나.","JPN":"千夏、あの生意気な小娘もあれ以降大人しくなってな。","ENG":"That cheeky little girl Chinatsu watched her behavior after that as well.","TWN":"千夏那個不知天高地厚的小鬼，從那時候開始也變得比較收斂。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"이 배신자! 죽여 버리겠어!","JPN":"この裏切者！　ぶっ殺してやる！","ENG":"You traitor! I will kill you!","TWN":"你這個叛徒！我要殺了你！"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NULL","text":{"KOREA":"으흐흐, 소꿉놀이도 집어치우고 발악하는 꼴이 볼 만하구나.","JPN":"ハハハ、いつものままごとすらやめて暴れておるわ。","ENG":"Hah hah, so you quit role playing? It suits you better, screaming and wailing.","TWN":"呵呵，你收起嬉皮笑臉，這麼激動的樣子，滿有看頭的。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NULL","text":{"KOREA":"그때 네 아비의 최후를 지켜보지 못한 것이 줄곧 마음에 걸렸지.","JPN":"あの時、お前の父親の死を見届けられなかったことだけが心残りだった。","ENG":"It was unfortunate that I missed watching your father’s death myself.","TWN":"我本來一直很遺憾，沒能親眼看到你父親的下場。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NULL","text":{"KOREA":"이제야 내 손으로 직접 카토리 가문을 끝장낼 수 있겠어.","JPN":"ようやくこの手で香取家を終わらせることができる。","ENG":"Finally, I can end the Katori line with my own hands.","TWN":"現在終於能夠親手除掉香取家族這個心頭之患！"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NULL","text":{"KOREA":"둘은 여기서 처리해라.","JPN":"二人はここで処理しろ。","ENG":"Kill them.","TWN":"把他們兩個給我處掉！"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELDER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NULL","text":{"KOREA":"사요도 방해꾼 몇 명쯤 없애는 건 상관없다고 했으니까.","JPN":"小夜も邪魔者が数人いなくなる程度構わないと言っていたからな。","ENG":"Sayo said she wouldn’t mind getting rid of a couple of rabble rousers.","TWN":"小夜也說過，可以消除幾個擋路的沒問題。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELDER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"SOLDIER_NPC_NULL_NULL","text":{"KOREA":"예. 장로님.","JPN":"はっ、長老。","ENG":"Yes, Elder.","TWN":"是，長老。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELDER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SOLDIER_NPC_NULL_NULL","text":{"KOREA":"우릴 너무 원망하진 마라. 하필 이런 중요한 시기에 끼어든 너희 잘못이니까.","JPN":"我々を恨むなよ。\\nこの大事な時に首を突っ込んだお前らが悪いんだ。","ENG":"Don’t blame us. You brought this on yourselves. You shouldn’t have meddled in our affairs.","TWN":"不要怪我們，誰叫你們偏偏要在這麼重要的時候來搗亂。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L13_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"장로!! 이 빌어먹을 영감이……!","JPN":"長老！！　このくそったれ……！","ENG":"Elder! You filthy old bastard!","TWN":"長老！！你這該死的臭老頭……！"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"방금 그 소리, 뭐야?","JPN":"今の音はなんだ？","ENG":"What was that sound?","TWN":"那是什麼聲音？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"잠금 장치가 풀리는 소리입니다. 못 다한 말씀은 이 누추한 곳을 나가서 하시죠.","JPN":"ロックが解除された音です。詳しくは後ほどご説明します。","ENG":"I opened the lock. Let’s get out of this place first, and then we’ll talk.","TWN":"是鎖解開的聲音，你還沒說完的話，等離開這個醜陋的地方再說吧。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"평범하게 말씀하시는 모습도 보기 좋습니다. 카토리 당주님.","JPN":"普通の口調の方が素敵ですよ、香取家当主様。","ENG":"Also, I like seeing you talk plainly, Mr. Katori.","TWN":"香取堂主，你正常說話的樣子很不錯。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L18_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"……어?","JPN":"……え？","ENG":"... Err?","TWN":"……喔？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L20_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NULL","text":{"KOREA":"어, 어떻게……! 열쇠는 분명 부하들이 압수했을 텐데!!","JPN":"ど、どうして……！　鍵は間違いなく部下たちが没収したはずなのに！！","ENG":"H-how? My men confiscated the key!","TWN":"怎…怎麼會…！鑰匙不是應該在我的手下那嗎！！"},"stage":{"bg":"PRISON_NIGHT","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NULL","text":{"KOREA":"카운터의 능력인가? 하지만 그 안에서는……!","JPN":"カウンターの能力なのか？　しかし、ここでは……！","ENG":"Is that your Counter ability? But you can’t use the power when you’re in the cell...","TWN":"是制裁者的能力嗎？可是在那裡面……！"},"stage":{"bg":"PRISON_NIGHT","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"카토리 가문은 차원함선을 관리해 온 기술자의 집안입니다, 장로님.","JPN":"長老、香取家は代々次元艦船を管理してきた技術者の家系です。","ENG":"Katoris are a family of engineers that have been fixing dimensional ships for generations, Elder.","TWN":"香取家族裡全都是管理次元艦船的技術人員，長老。"},"stage":{"bg":"PRISON_NIGHT","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"그렇기에 늘 모든 가능성에 일말의 대책을 남겨 두었지요.","JPN":"そのため、常にすべての可能性に対して対策を講じていたのです。","ENG":"They always have a contingency plan for every risk.","TWN":"保險起見，都會替自己留下後路。"},"stage":{"bg":"PRISON_NIGHT","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"이 감옥도 힘으로 열기에는 어려우나, 장로님 같은 이들로 인한 내분을 우려해 탈출할 구석을 만들어 두셨습니다.","JPN":"この監獄も力で開けることはできませんが、\\n長老のような方々による内紛の可能性を想定して、脱出方法を用意しておいたのです。","ENG":"You can’t force open this prison, but there is an escape route you can use in case of an emergency like this.","TWN":"這個監牢雖然很難靠蠻力打開，不過擔心你們這群長老會內鬨，所以有預留一個可以逃出去的地方。"},"stage":{"bg":"PRISON_NIGHT","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NULL","text":{"KOREA":"뭐, 뭐라고? 너 따위가 나도 모르는 사실을 어떻게 알고 있는 거냐?!","JPN":"な、なんだと？　お前ごときがわしも知らないことをなぜ知っておる！？","ENG":"W-what? How do you know of such things?","TWN":"什…什麼？這些事連我都不知道，你為什麼會知道？"},"stage":{"bg":"PRISON_NIGHT","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"그 해답은 스스로 유추해 보시죠, 장로님.","JPN":"長老、それはご自分でお考えください。","ENG":"Why don’t you figure it out yourself, Elder?","TWN":"你自己推測一下答案吧，長老。"},"stage":{"bg":"PRISON_NIGHT","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"그, 그 대답은……! 완벽한 흑막……!","JPN":"そ、その返しは……！　完璧な黒幕……！","ENG":"Y-your answer... That was very Shadow Group like!","TWN":"答案…就是…！完美的黑幕……！"},"stage":{"bg":"PRISON_NIGHT","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NULL","text":{"KOREA":"큭……! 고르디우스에서 귓동냥이라도 했나 보군……!","JPN":"くっ……！　ゴルディウスで何か聞いていたのか……！","ENG":"Darn... You must have overheard it from the Gordias.","TWN":"咳……！看來你在哥帝爾斯也耳濡目染不少……！"},"stage":{"bg":"PRISON_NIGHT","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ELDER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NULL","text":{"KOREA":"뭣들 하고 있느냐! 저놈들을 어서 죽이지 않고!!","JPN":"何をしている！　あいつらを早く始末しろ！！","ENG":"What are you doing? Kill them!","TWN":"你們愣著幹嘛！還不快給我殺掉他們！"},"stage":{"bg":"PRISON_NIGHT","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ELDER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"카토리 당주님, 싸우실 수 있으신지요.","JPN":"香取家当主様、戦えますか。","ENG":"Mr. Katori, can you fight?","TWN":"香取堂主，你能打吧？"},"stage":{"bg":"PRISON_NIGHT","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"훗……. 후후훗…….","JPN":"ふっ……ふふふっ……","ENG":"Hah... HAH HAH HAH!","TWN":"呵…… 呵呵呵……"},"stage":{"bg":"PRISON_NIGHT","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"이 몸께서 연합을 좀먹던 어둠을 그대로 놔둘 수야 없지!","JPN":"オレ様が連合を蝕む闇を放って置くわけがないだろう！","ENG":"I will not let the darkness stain the Alliance!","TWN":"怎麼能放過這些讓聯盟腐敗的害蟲呢！"},"stage":{"bg":"PRISON_NIGHT","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"덤벼라, 조무래기들! 모조리 내 흑염의 제물로 삼아 줄 테니!","JPN":"かかってこい、雑魚ども！　全員オレ様の黒炎の餌食にしてやる！","ENG":"Bring it on, small fry! You’ll fall before my dark flame!","TWN":"來吧，你們這些傢伙！ 全都來成為黑炎的祭物吧！"},"stage":{"bg":"PRISON_NIGHT","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};